"""
MKT Christ Commentary — 2 Samuel chapters 14–16
Run: python3 scripts/zc-christ-2samuel-14-16.py

Christological classification:
- Ch14 centers on the Tekoa woman's parable — esp. v14's statement that
  God devises means so the banished will not stay banished (gospel logic)
- Ch15: David's Olivet ascent weeping/barefoot, Kidron crossing, Ittai's
  loyalty oath (Gentile remnant pattern), and submission prayer
- Ch16: Shimei cursing the humiliated king (Christ receiving curses as king),
  David's submission to the curse as potentially divine, and Ahithophel
  as false counselor / Judas type

Every verse requires an entry; brief entries acceptable for transitional verses.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "14": {
    "1": "<p>A theme: Joab perceives that &lsquo;the king&rsquo;s heart was set on Absalom&rsquo; — the father&rsquo;s disposition of longing for the lost son is the emotional background of everything that follows. The divine Father&rsquo;s heart set on restoring the banished is the theological premise of the gospel; the entire mechanism of the Tekoa woman&rsquo;s parable is Joab&rsquo;s attempt to create the opening through which David&rsquo;s already-existing mercy can act. God&rsquo;s heart is not persuaded to mercy by Christ&rsquo;s intercession — it is already merciful; Christ opens the way for that mercy to act within justice.</p>",
    "2": "<p>A theme: Joab sends the Tekoa woman to act a parable before the king — the use of a human instrument bearing a scripted message to bring about a predetermined outcome. The parallel to the prophetic role is exact: the prophet does not speak his own words but those given him by another. The woman&rsquo;s role anticipates the NT apostolic pattern: emissaries bearing a message about the restoring of the banished (2 Cor 5:19-20, &lsquo;God was reconciling the world to himself in Christ... and has committed to us the ministry of reconciliation&rsquo;).</p>",
    "3": "<p>A theme: &lsquo;Joab put the words in her mouth&rsquo; — the Tekoa woman speaks what she has been given to speak. This is the prophetic inspiration formula in narrative form: the prophet&rsquo;s speech is the word of another speaking through them (cf. 2 Sam 23:2: &lsquo;The Spirit of the LORD speaks through me; his word is on my tongue&rsquo;). The words that David will hear about the banished son coming home are not the woman&rsquo;s improvisation but a prepared message — as the gospel is prepared speech, the eternal plan of God encoded in testimony.</p>",
    "4": "<p>A theme: The woman fell on her face and bowed low with her petition — the posture of a petitioner before the royal judge who alone can solve the otherwise insoluble problem. The appeal &lsquo;Help me, O king!&rsquo; (<em>hôšîʿāh hammelek</em>) is the same root as &lsquo;save&rsquo; — she is asking for salvation from a legal threat she cannot escape on her own. This is the posture of prayer before Christ the King: the approach of one who cannot save themselves, appealing to the sovereign who can.</p>",
    "5": "<p>A theme: The widow&rsquo;s situation — husband dead, two sons left — is the narrative setup for the theological problem the parable will raise. The widow whose protector has died and whose remaining family is now threatened by legal demand represents the human condition: exposed, without covenantal cover, and facing a claim that cannot be met. The gospel addresses exactly this condition: those without a mediator, facing the demand of divine justice, need the intervention the woman seeks from the king.</p>",
    "6": "<p>A shadow: Two brothers, one killing the other in a field — the Cain and Abel structure (Gen 4) recurs in the parable. The fratricide is the archetypal human sin that disrupts the family unit and places the survivor under the threat of blood-vengeance. The woman&rsquo;s parable uses this primal narrative because it is the most universal form of the guilt-and-threat structure that the gospel addresses: the sin that creates the enmity that demands satisfaction.</p>",
    "7": "<p>A theme: &lsquo;Hand over the one who killed his brother, that we may put him to death for the life of his brother&rsquo; — the clan&rsquo;s demand is the law&rsquo;s demand: blood for blood, life for life. The threat to &lsquo;destroy the heir as well&rsquo; adds the covenantal dimension: not merely punishment of the individual but the extinction of the family line. The law&rsquo;s demand that the guilty die threatens not only the individual but all who depend on him. This is precisely the force of sin&rsquo;s claim: it does not merely destroy the sinner but all who are in him (Rom 5:12).</p>",
    "8": "<p>A theme: The king&rsquo;s decision to intervene — &lsquo;I will give orders on your behalf&rsquo; — is the exercise of royal prerogative over the strict application of the law. The king has the authority to issue a decree that supersedes the blood-avenger&rsquo;s legal claim. The theological principle is that the King&rsquo;s decision precedes and enables the legal mechanism by which guilt is covered; the decree of mercy is prior to the instrument of mercy. God&rsquo;s decision to save precedes the incarnation that accomplishes it.</p>",
    "9": "<p>A shadow: &lsquo;My lord the king, let the guilt (<em>ʿāwōn</em>) fall on me and my father&rsquo;s house; let the king and his throne be guiltless.&rsquo; The woman offers herself as the guilt-bearer so that the king can act mercifully without legal contamination. This is the substitution pattern: a willing party absorbs the guilt so the king can be both just and merciful. The NT&rsquo;s answer to the legal problem of forgiveness is Christ taking the guilt so God can be &lsquo;just and the one who justifies&rsquo; (Rom 3:26).</p>",
    "10": "<p>A theme: The king&rsquo;s protection — &lsquo;Bring him to me and he shall not touch you again&rsquo; — is the royal guarantee of sanctuary. The king places himself between the legal claimant and the vulnerable widow. This is the protective function of Christ as High Priest and Advocate: &lsquo;If anyone sins, we have an Advocate with the Father, Jesus Christ the righteous&rsquo; (1 John 2:1). The Advocate stands between the accuser and the accused, interposing royal authority.</p>",
    "11": "<p>A revelation of God: &lsquo;Please let the king invoke the LORD your God, so that the avenger of blood may not add to the destruction&rsquo; — the woman invites David to make an oath in YHWH&rsquo;s name, binding himself legally to protect the surviving son. David&rsquo;s oath — &lsquo;As YHWH lives, not a hair of your son shall fall to the ground&rsquo; — is the royal oath of absolute protection. The formula &lsquo;not a hair of your son shall fall&rsquo; is the same absolute-protection idiom Jesus uses: &lsquo;even the hairs of your head are all numbered&rsquo; (Matt 10:30), the divine protection that is total and particular.</p>",
    "12": "<p>A theme: &lsquo;Please let your servant say one more word&rsquo; — the woman&rsquo;s bold approach to the king for a second petition, after receiving the first. The pattern of bold intercession — pressing the king repeatedly for mercy — reflects the NT&rsquo;s teaching on persistent prayer (Luke 18:1-8, the persistent widow before the unjust judge). The woman is both petitioner and intercessor; her second word will make explicit what her first word implied about the king&rsquo;s own situation.</p>",
    "13": "<p>A shadow: &lsquo;Why then have you made such a plan against the people of God?&rsquo; — the parable applied: David&rsquo;s ruling in the widow&rsquo;s case commits him to the very mercy he has refused to Absalom. The prophetic function of the parable (like Nathan&rsquo;s &lsquo;You are the man&rsquo; in ch12) is to make the king see his own behavior from outside. Judgment that begins with mercy in a parable must be consistent: the God who declares the banished son welcome cannot simultaneously bar his own rebellious children from return.</p>",
    "14": "<p>A direct revelation: &lsquo;We all must die; we are like water poured out on the ground that cannot be gathered back. But God does not take away life, but devises means (<em>ḥāšab maḥăšāḇôt</em>) so that the banished one will not remain banished (<em>yiddaḥ</em>) from him.&rsquo; This is the most explicit pre-NT statement of the gospel logic in the narrative books. &lsquo;God devises means&rsquo; — the divine <em>ḥāšab</em> (plans/thinks/devises) is the same root as &lsquo;it was credited to him as righteousness&rsquo; (Gen 15:6; Rom 4:3-8). God plans and executes the mechanism of return for those who are banished — which is precisely the incarnation, cross, and resurrection: the &lsquo;means&rsquo; God devised so that the banished race would not remain banished from him forever.</p>",
    "15": "<p>A theme: The woman&rsquo;s personal application — &lsquo;the people frightened me... your servant thought, I will speak to the king&rsquo; — models the movement from fear to prayer. The logic is: people threaten, so turn to the king. This is the NT&rsquo;s direction for anxiety: &lsquo;Do not be anxious about anything, but in everything by prayer and supplication with thanksgiving let your requests be made known to God&rsquo; (Phil 4:6). The woman moves from the fear of human power to trust in royal power — the basic movement of faith.</p>",
    "16": "<p>A theme: &lsquo;The king will listen and rescue his servant from the hand of the man who would destroy both me and my son from the inheritance of God.&rsquo; The inheritance of God (<em>naḥălat ʾĕlōhîm</em>) is at stake — not merely personal survival but the covenantal portion that belongs to YHWH&rsquo;s people. The king&rsquo;s rescue preserves the inheritance. Christ&rsquo;s work rescues not merely individuals but their covenantal inheritance: &lsquo;an inheritance that is imperishable, undefiled, and unfading, kept in heaven for you&rsquo; (1 Pet 1:4).</p>",
    "17": "<p>A type: &lsquo;My lord the king is like the angel of God (<em>malʾāḵ hāʾelōhîm</em>) — discerning good and evil.&rsquo; The comparison of the king to the angel of God for judicial discernment appears three times in the Samuel narrative (here; 14:20; 19:27). In the OT the angel of God is the divine emissary who carries YHWH&rsquo;s authority and executes his will. The king-as-angel comparison establishes the typological linkage between the human royal judge and the divine representative — a trajectory that leads to Christ, who is both King and the divine Word in person (John 1:1, 14).</p>",
    "18": "<p>A theme: The king&rsquo;s direct question — &lsquo;Do not hide from me what I am about to ask you&rsquo; — and the woman&rsquo;s oath before YHWH establishes the judicial context of transparent truth. The divine Judge who questions the soul does not accept concealment: &lsquo;Nothing in all creation is hidden from God&rsquo;s sight; everything is uncovered and laid bare before the eyes of him to whom we must give account&rsquo; (Heb 4:13). The moment of honest royal inquiry is the judicial archetype of the final account before Christ.</p>",
    "19": "<p>A theme: &lsquo;Is Joab behind all of this?&rsquo; — David&rsquo;s discernment that a human intermediary has arranged the whole affair reveals both the king&rsquo;s wisdom and the indirect way that divine restoration is often accomplished: through human instruments whose involvement the divine King sees through. God&rsquo;s providential use of human agents does not make those agents the cause — David&rsquo;s mercy for Absalom exists prior to Joab&rsquo;s mechanism; the instrument only creates the opportunity for the prior mercy to act.</p>",
    "20": "<p>A theme: &lsquo;My lord is wise like the wisdom of an angel of God to know all that is on the earth&rsquo; — the second angel-comparison in this chapter, extended to omniscient wisdom (knowing &lsquo;all that is on the earth&rsquo;). The trajectory from human royal wisdom to divine omniscience is completed in Christ: &lsquo;in whom are hidden all the treasures of wisdom and knowledge&rsquo; (Col 2:3). The king&rsquo;s wisdom that perceives what is hidden anticipates the divine wisdom that knows &lsquo;the thoughts and intentions of the heart&rsquo; (Heb 4:12).</p>",
    "21": "<p>A type: David&rsquo;s decree — &lsquo;I have decided: go and bring back the young man Absalom&rsquo; — is the father&rsquo;s sovereign act of restoration. The father&rsquo;s decision to bring back the son who had fled in guilt is the parable of the prodigal son (Luke 15:20) in its narrative form: the father runs to meet the returning son. The divine decision to restore the banished is not extracted by legal argument but flows from the father&rsquo;s own character. The king wills the restoration; the instrument (Joab) executes it; the son receives it as gift.</p>",
    "22": "<p>A theme: Joab&rsquo;s joy — &lsquo;Today your servant knows that I have found favor in your eyes, my lord the king&rsquo; — is the joy of the one whose mediation has succeeded, whose petition for mercy has been heard. The mediator&rsquo;s satisfaction in seeing mercy extended is the joy of Christ: &lsquo;who for the joy that was set before him endured the cross&rsquo; (Heb 12:2). The joy of the Father&rsquo;s house over the returning son (Luke 15:22-24) is the divine version of Joab&rsquo;s joy at the king&rsquo;s decree of restoration.</p>",
    "23": "<p>A theme: Absalom is brought back to Jerusalem — the banished son physically restored to the city. This is partial fulfillment of the father&rsquo;s desire (v1: the king&rsquo;s heart was set on Absalom). But the full reconciliation does not yet occur — Absalom is in the city but not in the presence of the king (v24). The physical return without relational restoration is a warning: proximity to the covenant community without the Father&rsquo;s face is not salvation. The restoration that matters is not geographic but relational.</p>",
    "24": "<p>A shadow: &lsquo;He may go to his own house, but he shall not appear before me.&rsquo; David&rsquo;s partial mercy — return to Jerusalem but not to the royal presence — is theologically inadequate as a model of restoration. The shadow is by contrast: the gospel does not bring people back to the periphery of God&rsquo;s presence; it brings them into the throne room. &lsquo;Let us then approach God&rsquo;s throne of grace with confidence&rsquo; (Heb 4:16) — the Christ-mediated access to the Father&rsquo;s face is complete, not partial. Absalom&rsquo;s two-year exclusion from David&rsquo;s face is what the gospel removes.</p>",
    "25": "<p>A shadow: &lsquo;In all Israel no one was as widely admired for his beauty as Absalom; from the sole of his foot to the crown of his head there was no blemish in him.&rsquo; The physical perfection of Absalom mirrors the initial description of Saul (1 Sam 9:2: &lsquo;a choice young man; there was no one more handsome&rsquo;) — both are physically ideal kings whose inner failure disqualifies them. Absalom&rsquo;s blemish-free beauty stands in ironic contrast to Christ, of whom Isaiah says: &lsquo;He had no form or majesty that we should look at him, and no beauty that we should desire him&rsquo; (Isa 53:2). The true king&rsquo;s beauty is hidden; the false king&rsquo;s is on display.</p>",
    "26": "<p>A shadow: Absalom&rsquo;s hair — weighing 200 shekels by the royal standard at the annual cutting — is the visible symbol of his vaunted glory. The Nazirite tradition (Num 6:1-21) tied hair to consecrated devotion; Samson&rsquo;s hair was his strength and its loss his undoing. Absalom&rsquo;s hair is pride — it makes him conspicuous, admired, and ultimately lethal: it catches in the oak tree (18:9) and suspends him between heaven and earth. The very glory he is famous for becomes the instrument of his death. The false glory that exalts itself is precisely what is brought low at the cross (Phil 2:8-9).</p>",
    "27": "<p>A theme: Absalom&rsquo;s daughter named Tamar perpetuates the name of the sister who was violated in the preceding chapter&rsquo;s narrative context (ch13). The naming of a daughter after a violated woman is either an act of honor (memorializing the wrong done) or an unconscious repetition of the damaged covenant line. The persistence of wounded names in the covenant genealogy is the human side of what grace must address: it is not only individuals but the accumulated damage of generational sin that the gospel heals (the &lsquo;restoration of all things,&rsquo; Acts 3:21).</p>",
    "28": "<p>A theme: Two full years of estrangement — Absalom in Jerusalem, never appearing before the king. This is the condition of estrangement that the gospel resolves: near to the covenant community in location, but excluded from the Father&rsquo;s face. Paul describes the Gentile condition as &lsquo;alienated from the commonwealth of Israel... having no hope and without God in the world. But now in Christ Jesus you who once were far off have been brought near&rsquo; (Eph 2:12-13). The two-year distance between Absalom and David is the human picture of the estrangement that Christ abolished.</p>",
    "29": "<p>A theme: Absalom&rsquo;s repeated attempt to summon Joab — the mediator who will not come. When access to the king is blocked, Absalom can only act through an intermediary who must first be made available. The NT&rsquo;s answer to the problem of inaccessible intercession is that the Mediator is permanently available: &lsquo;he is able to save completely those who come to God through him, because he always lives to intercede for them&rsquo; (Heb 7:25). The Mediator who cannot be summoned away is the one who &lsquo;always lives.&rsquo;</p>",
    "30": "<p>A shadow: Absalom burns Joab&rsquo;s field to force his attention — coercion of the mediator. The method reveals Absalom&rsquo;s character: unable to access the king through legitimate petition, he uses destructive pressure to compel the intermediary to act. This is the antithesis of the NT&rsquo;s approach to intercession, which is built on the confidence of a right relationship rather than coercion. &lsquo;Let us approach with a true heart in full assurance of faith&rsquo; (Heb 10:22) — the access is legitimate, not coerced.</p>",
    "31": "<p>A theme: Joab confronts Absalom — the mediator responds to the pressure but also challenges the method. The mediator who can be both summoned and confronted is a fully human figure operating in a complex political relationship. Christ&rsquo;s intercession operates in a different register: not compelled but chosen, not confronted but freely offered. The contrast between Joab&rsquo;s reluctant mediation and Christ&rsquo;s eager intercession marks the difference between the types and their fulfillment.</p>",
    "32": "<p>A theme: Absalom&rsquo;s appeal — &lsquo;Let me come before the king; if I am guilty of anything, let him put me to death&rsquo; — is the appeal for direct access over indirect intermediary access, and a bold offer to accept the full penalty of the king&rsquo;s judgment. The willingness to submit to the king&rsquo;s judgment rather than remain in ambiguous half-acceptance is the posture that Christ enables: full exposure before the Father, confident that the verdict will be &lsquo;righteous&rsquo; because of the Son&rsquo;s mediation.</p>",
    "33": "<p>A type: The kiss of reconciliation — David summoning Absalom and Absalom bowing with his face to the ground, David kissing him. This is the prodigal son narrative (Luke 15:20: &lsquo;he ran and embraced him and kissed him&rsquo;) in its OT type. The king&rsquo;s kiss is the most intimate act of restoration — not merely pardon at a distance but full personal restoration. The gospel&rsquo;s offer is not merely legal acquittal but the Father&rsquo;s embrace: &lsquo;See what kind of love the Father has given us, that we should be called children of God; and so we are&rsquo; (1 John 3:1).</p>"
  },
  "15": {
    "1": "<p>A shadow: Absalom&rsquo;s chariot, horses, and fifty runners — the visible apparatus of royal power that contrasts with the humble king. Zechariah 9:9 describes the messianic king coming &lsquo;humble and riding on a donkey&rsquo; — precisely the antithesis of the chariot-and-horses display. Jesus&rsquo;s deliberate choice of a donkey for the Triumphal Entry (Matt 21:5) enacts the Zech 9:9 contrast: the true king does not appear in Absalom&rsquo;s glory. The false king&rsquo;s military display and the true king&rsquo;s humble entry are mirror images across the canonical distance.</p>",
    "2": "<p>A shadow: Absalom positioned at the gate to intercept those seeking justice from the king — the false shepherd inserting himself between the people and their legitimate shepherd-king. Jesus&rsquo;s accusation of the scribes and Pharisees applies: &lsquo;You shut the door of the kingdom of heaven in people&rsquo;s faces. You yourselves do not enter, nor will you let those enter who are trying to&rsquo; (Matt 23:13). The false mediator who stands at the gate to redirect seekers is the type of every form of false spiritual authority that exploits access to the king.</p>",
    "3": "<p>A shadow: &lsquo;Your case is good and just, but there is no one assigned by the king to hear it&rsquo; — Absalom creates the false impression that the king is inaccessible and disinterested, then presents himself as the solution. The lie at the heart of the false shepherd&rsquo;s pitch is that the true King is indifferent or unavailable. The gospel&rsquo;s answer is explicit: &lsquo;Come to me, all who are weary and burdened&rsquo; (Matt 11:28); &lsquo;whoever comes to me I will never drive away&rsquo; (John 6:37). The true King is not absent but available; the false shepherd&rsquo;s premise is a lie.</p>",
    "4": "<p>A shadow: &lsquo;If only I were made judge in the land — I would give everyone justice!&rsquo; — the self-appointment of the false shepherd as the solution to the true shepherd&rsquo;s failures. The messianic pretender always presents himself as the just alternative to the current king. The true Judge — Christ — is appointed not by popular acclamation but by the Father (&lsquo;The Father judges no one, but has entrusted all judgment to the Son,&rsquo; John 5:22). The authority to judge comes from divine appointment, not from self-assertion or popular approval.</p>",
    "5": "<p>A shadow: Absalom reaching out, taking each person, and kissing them — the false shepherd&rsquo;s physical intimacy as a tool of loyalty-stealing. The physical gesture of welcome (&lsquo;taking hold of him and kissing him&rsquo;) mimics genuine pastoral care. Jesus warns of false prophets who &lsquo;come to you in sheep&rsquo;s clothing, but inwardly are ferocious wolves&rsquo; (Matt 7:15). The false shepherd&rsquo;s affection is the instrument of capture, not genuine care.</p>",
    "6": "<p>A shadow: &lsquo;Absalom stole the hearts of the men of Israel&rsquo; (<em>wəyignōb ʾaḇšālôm ʾet lēḇ</em>) — the theft vocabulary applied to the winning of loyalties. The hearts that belong to David (the anointed king) are being taken by stealth. In John 10:10 Jesus describes the false shepherd as &lsquo;the thief who comes only to steal and kill and destroy&rsquo; — the anti-shepherd whose method is theft. Absalom&rsquo;s heart-theft is the narrative form of what John 10 describes in its abstract: the false shepherd who takes what belongs to the true one.</p>",
    "7": "<p>A shadow: Absalom using a religious vow as cover for political conspiracy — &lsquo;Let me go to Hebron and pay the vow I made to the LORD.&rsquo; The exploitation of sacred pretense for political ends is the recurring pattern of false religion: the sacred is invoked not as genuine devotion but as cover for the will to power. Jesus consistently exposed this pattern in the Pharisees (Matt 23:5: &lsquo;They do all their deeds to be seen by others&rsquo;). The genuinely sacred vow vs. the politically exploited religious gesture is the distinction between authentic and false worship.</p>",
    "8": "<p>A theme: Absalom&rsquo;s vow — &lsquo;If the LORD brings me back to Jerusalem, I will worship the LORD in Hebron&rsquo; — frames a conditional covenant with God. The conditional vow is a legitimate form of religious expression (Gen 28:20-22, Jacob at Bethel); what makes Absalom&rsquo;s vow culpable is that its fulfillment is used as a pretext for rebellion. The legitimacy of religious form does not guarantee purity of motive — a warning about religious practice divorced from genuine covenantal submission.</p>",
    "9": "<p>A theme: &lsquo;Go in peace.&rsquo; David&rsquo;s blessing on the departure he does not know is a rebellion — the anointed king unknowingly blesses the conspiracy against himself. The irony recalls the passion narrative: Judas leaves the upper room with Jesus&rsquo;s knowledge (&lsquo;What you are going to do, do quickly,&rsquo; John 13:27) but David&rsquo;s blessing of Absalom is without such foreknowledge. The king&rsquo;s unwitting blessing on the betrayer establishes the poignancy of the coming betrayal.</p>",
    "10": "<p>A shadow: The secret messengers sent throughout the tribes — &lsquo;As soon as you hear the trumpet, say, &ldquo;Absalom is king in Hebron!&rdquo;&rsquo; — the conspiracy that uses the royal trumpet-signal (&lsquo;Absalom is king&rsquo;) as its announcement. The co-opting of legitimate royal symbols (the trumpet, the declaration of kingship) for the false king&rsquo;s installation is the eschatological anti-Christ pattern: using the forms of legitimate authority to establish false rule. The true King&rsquo;s return will be announced by &lsquo;the trumpet of God&rsquo; (1 Thess 4:16) — unmistakable and unappropriable.</p>",
    "11": "<p>A theme: Two hundred men who &lsquo;went in all innocence, knowing nothing&rsquo; — bystanders swept up in a rebellion they did not understand. The innocent who follow the false shepherd not because they have chosen him but because they do not know the full situation are the object of the true shepherd&rsquo;s pastoral concern: &lsquo;When he saw the crowds, he had compassion on them, because they were harassed and helpless, like sheep without a shepherd&rsquo; (Matt 9:36). The uninformed followers of the false king are not his willing partisans but victims of his deception.</p>",
    "12": "<p>A type: Ahithophel the counselor defecting to Absalom — one of David&rsquo;s trusted advisors (2 Sam 16:23: &lsquo;his counsel was as if one had inquired of God&rsquo;) joining the conspiracy. The betrayal of David by his trusted counselor Ahithophel has a direct NT typological application: Ps 41:9 — &lsquo;Even my close friend in whom I trusted, who ate my bread, has lifted his heel against me&rsquo; — is applied to Judas in John 13:18. Jesus himself applies the David-Ahithophel betrayal pattern to his own situation. Ahithophel is the OT&rsquo;s primary Judas type.</p>",
    "13": "<p>A type: &lsquo;The hearts of the Israelites have turned to Absalom&rsquo; — the news of widespread defection reaches David. The humiliated king hearing that his own people have abandoned him for the false king is the passion narrative&rsquo;s structure: &lsquo;He came to his own, and his own people did not receive him&rsquo; (John 1:11). The rejection of the anointed by his own nation is the typological structure that Jesus entered consciously, citing Ps 22:1 from the cross: the anointed abandoned by the very community he came to serve.</p>",
    "14": "<p>A type: David&rsquo;s decision to flee rather than defend Jerusalem — &lsquo;We must flee, or none of us will escape from Absalom&rsquo; — is the beginning of the humiliated king&rsquo;s withdrawal. The kenotic descent — the king choosing vulnerability rather than defensive power — prefigures Christ&rsquo;s non-resistance at the passion: &lsquo;Do you think I cannot call on my Father, and he will at once put at my disposal more than twelve legions of angels?&rsquo; (Matt 26:53). David could have defended Jerusalem militarily; Christ could have called the angels. Both chose the path of withdrawal and suffering.</p>",
    "15": "<p>A theme: &lsquo;We are ready to do whatever my lord the king decides&rsquo; — the loyal remnant&rsquo;s unconditional commitment to the humiliated king. The small group that remains with David through the flight represents the faithful remnant that accompanies the rejected King — the disciples who stay when &lsquo;many turned back and no longer followed him&rsquo; (John 6:66). Peter&rsquo;s response — &lsquo;Lord, to whom shall we go? You have the words of eternal life&rsquo; (John 6:68) — is the NT version of the servants&rsquo; loyalty.</p>",
    "16": "<p>A theme: David leaves ten concubines to keep the palace — vulnerability imposed by the flight, not desired. The king&rsquo;s departure exposes those under his care to the coming occupation. This is not the shepherd abandoning his flock but the shepherd forced into flight while some of his household cannot move. The pastoral anguish of leaving the vulnerable behind is part of the cost of the king&rsquo;s passion-walk; Christ&rsquo;s cry of desolation (&lsquo;My God, my God, why have you forsaken me?&rsquo;) is the absolute form of this abandonment-in-mission.</p>",
    "17": "<p>A theme: The people stopping at the edge of the city — the final pause before the king fully departs the holy city. The departure of the anointed from Jerusalem is the anti-Triumphal-Entry: what began with the ark coming in (ch6) is now the king going out. The departure of the divine presence from the city is the theological crisis that Ezekiel 11:22-23 records for the final destruction: the glory departing from the temple. David&rsquo;s exodus from Jerusalem presages the final departure of the divine king.</p>",
    "18": "<p>A theme: All the servants marching past the king — the review of loyal forces before the flight. The Gittites (600 men who had come from Gath with David, v18) represent foreign-born troops who have attached themselves to the humiliated king. The gathering of those who follow the rejected king out of the city is the remnant pattern: a diverse group of people who remain loyal when the institutional support has collapsed, as the disciples regrouped after the crucifixion.</p>",
    "19": "<p>A type: David&rsquo;s offer to Ittai the Gittite — &lsquo;Go back and stay with the new king&rsquo; — is the humiliated king releasing a Gentile from obligation. David acknowledges that Ittai arrived &lsquo;only yesterday&rsquo; and has no prior covenant bond requiring him to suffer the king&rsquo;s exile. The offer of release to the Gentile is the king&rsquo;s own act of grace: he does not compel loyalty from those without a prior covenant obligation. Christ does not compel; he invites.</p>",
    "20": "<p>A type: &lsquo;Should I today make you wander with us, going I do not know where?&rsquo; — David&rsquo;s honest uncertainty about where the exile will lead. The king who does not know where he is going, inviting followers into that uncertainty, is the pattern of Jesus&rsquo;s call: &lsquo;Follow me&rsquo; (Matt 4:19; 8:22) without specified destination. The disciples who follow &lsquo;going I do not know where&rsquo; are those who have committed to the person of the king rather than the security of a destination. David blesses and releases Ittai — the grace of the king even in extremity.</p>",
    "21": "<p>A type: Ittai&rsquo;s loyalty oath — &lsquo;As the LORD lives, and as my lord the king lives, wherever my lord the king may be — whether in death or life, there your servant will be&rsquo; — is structurally identical to Ruth&rsquo;s oath to Naomi (Ruth 1:16-17): a Gentile making an unconditional loyalty covenant with one who is departing into exile and loss. The Gentile loyalty to the humiliated king is a type of the Gentile church&rsquo;s attachment to the rejected Christ: joining the fellowship of his sufferings (Phil 3:10) without the guarantee of immediate triumph.</p>",
    "22": "<p>A theme: David&rsquo;s acceptance of Ittai&rsquo;s loyalty and the march forward together. The community of the rejected king — diverse in origin, unified in commitment — crosses the Kidron together. The fellowship of those who follow the humiliated king into the wilderness is the early church&rsquo;s self-understanding: &lsquo;bearing the disgrace he bore. For here we have no enduring city, but we seek the city that is to come&rsquo; (Heb 13:13-14). The march of the faithful out of Jerusalem anticipates the church&rsquo;s pilgrim existence.</p>",
    "23": "<p>A type: Crossing the Wadi Kidron — all the people crossing while the king crosses on foot, weeping aloud. John 18:1 explicitly notes that Jesus &lsquo;crossed the Kidron Valley&rsquo; to Gethsemane before his arrest. The typological connection is exact: the anointed king crossing the Kidron in humiliation, weeping, on his way to the Mount of Olives, while his people weep. David&rsquo;s Kidron crossing is the OT type of Jesus&rsquo;s Kidron crossing; both are movements from the city of God&rsquo;s house toward the hill of anguished prayer.</p>",
    "24": "<p>A revelation of God: Zadok and the Levites bring the ark out of Jerusalem, but David sends it back. The ark is the symbol of divine presence; David refuses to take it with him. This is one of the most theologically profound acts in the Samuel narrative: the king in extremity will not use the ark as a magical talisman. &lsquo;If I find favor in the LORD&rsquo;s eyes, he will bring me back&rsquo; — David separates his personal fate from the ark&rsquo;s fate. The presence of God is not an instrument to be controlled; it is a gift to be received in faith. Christ&rsquo;s Gethsemane prayer — &lsquo;not as I will, but as you will&rsquo; (Matt 26:39) — is the same non-manipulation of divine presence.</p>",
    "25": "<p>A revelation of God: &lsquo;Carry the ark of God back into the city. If I find favor in the LORD&rsquo;s eyes, he will bring me back and show me both it and his dwelling place.&rsquo; David&rsquo;s separation of his personal fate from the ark — &lsquo;if I find favor&rsquo; — is the submission of the anointed to the divine will. This is not resignation but the active trust of one who knows that his continuation in power depends entirely on YHWH&rsquo;s choice. The covenant king has no autonomous claim on the divine presence; it is given and withheld freely. The same theology governs Christ&rsquo;s submission in Gethsemane.</p>",
    "26": "<p>A revelation of God: &lsquo;But if he says, &ldquo;I take no pleasure in you&rdquo; — then here I am. Let him do with me whatever seems good to him.&rsquo; This is the absolute submission of the anointed to the divine will, even in the face of rejection. The willingness of the king to accept the possibility that YHWH may withdraw his favor — and to submit to whatever that means — is the deepest form of covenant trust. Gethsemane is this verse absolutized: &lsquo;Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done&rsquo; (Luke 22:42).</p>",
    "27": "<p>A theme: David sends the priests back as a spy network — Zadok and Abiathar as intelligence assets in the city. The use of legitimate priestly figures for strategic purposes in the crisis shows the king deploying every available resource for survival. The pastoral and prophetic offices being conscripted for the king&rsquo;s service in extremity anticipates the NT&rsquo;s picture of all gifts deployed in service of the crucified and risen Lord: the whole body of Christ functioning for his purposes even in the &lsquo;wilderness&rsquo; period before his return.</p>",
    "28": "<p>A theme: &lsquo;I will wait at the crossings of the wilderness until word comes from you.&rsquo; The king in the wilderness, waiting for intelligence from his contacts in the city — the liminal position between the city of God&rsquo;s house (Jerusalem) and the wilderness of exile. The church&rsquo;s position is exactly this: the Lord has crossed the Kidron, ascended the Mount of Olives, and departed; we wait in the wilderness between the first and second coming, receiving reports from his representatives (&lsquo;word comes from you&rsquo;) — the ongoing testimony of Scripture and Spirit.</p>",
    "29": "<p>A theme: The ark returns to Jerusalem and stays there. The divine presence, represented by the ark, remains in the city while the anointed king wanders in exile. The separation of the covenant-symbol from the covenant-king during the passion-walk is the pattern of the incarnation&rsquo;s wilderness period: Christ present with the Father in glory while his people wait. The ark in the city is the promise of eventual return — the divine presence that will welcome the king back when the exile ends.</p>",
    "30": "<p>A type: David ascending the Mount of Olives weeping, head covered, feet bare, all the people with him covering their heads and weeping — the via dolorosa in its OT form. Luke 19:41-44 records Jesus weeping over Jerusalem as he descended the Mount of Olives toward the city. David ascending the Mount of Olives in grief, Jesus descending in grief — both movements express the anointed king&rsquo;s anguish over the city that has rejected him. The bare feet are a sign of mourning and humiliation; Jesus&rsquo;s passion journey includes the literal stripping at the crucifixion.</p>",
    "31": "<p>A type: &lsquo;David said, &ldquo;O LORD, please make the counsel of Ahithophel foolishness.&rdquo;&rsquo; — the prayer against the false counselor who has joined the conspiracy. Jesus cites Ps 41:9 (applying the David-Ahithophel betrayal to Judas) explicitly in John 13:18. David&rsquo;s prayer that Ahithophel&rsquo;s counsel would be overruled (answered through Hushai in ch17) is the OT type of God&rsquo;s overruling of the plans of those who conspired against the anointed — including the Sanhedrin&rsquo;s conspiracy, overruled by the resurrection.</p>",
    "32": "<p>A theme: Hushai the Archite meeting David at the top of the Mount of Olives — the faithful friend who meets the king at the summit. The Mount of Olives summit is the place of both grief (David weeping, v30) and meeting (Hushai coming with torn coat and dirt on his head — the mourning posture). The gathering of the faithful at the king&rsquo;s lowest point is the NT&rsquo;s picture of the disciples at the cross and the women at the tomb: those who do not abandon the humiliated king but meet him in his grief.</p>",
    "33": "<p>A theme: David&rsquo;s honest assessment of Hushai — &lsquo;If you go on with me, you will only be a burden to me&rsquo; — is not rejection but strategic deployment. The king who does not force his followers to share his suffering when they can better serve him by returning is the pastor-king who thinks of his people&rsquo;s welfare even in his own crisis. Jesus at the arrest: &lsquo;Let these men go&rsquo; (John 18:8) — protecting his followers even while being taken himself.</p>",
    "34": "<p>A type: David sends Hushai back as a counter-spy — &lsquo;Say to Absalom, &ldquo;I will be your servant, O king; I was your father&rsquo;s servant before, but now I will be your servant.&rdquo;&rsquo; The instruction to use technically true but misleading speech to protect the true king&rsquo;s interests is the framework for understanding the disciples&rsquo; own ambiguous position in the world: &lsquo;sent as sheep in the midst of wolves; so be wise as serpents and innocent as doves&rsquo; (Matt 10:16). The faithful agent operating in hostile territory serves the king&rsquo;s purposes precisely by being present rather than absent.</p>",
    "35": "<p>A theme: Zadok and Abiathar as the priests who will receive and relay intelligence from the palace — the priestly office functioning as a network of covenant communication during the king&rsquo;s absence. The priests who maintain the communication between the exiled king and the events unfolding in the city are the archetype of the prophetic and pastoral office in the NT: those who keep the line of communication between the absent Lord and his people open during the interim between departure and return.</p>",
    "36": "<p>A theme: Ahimaaz and Jonathan (the priests&rsquo; sons) as message-carriers — the next generation deployed for the king&rsquo;s information network. The use of the priestly family&rsquo;s younger generation for covenant service in the crisis anticipates the apostolic commission: the mission is entrusted to those who will carry it forward into situations the original messengers cannot access directly (Acts 1:8, the graduated mission from Jerusalem to the ends of the earth).</p>",
    "37": "<p>A theme: Hushai returns to the city just as Absalom arrives — the providential timing of the faithful agent arriving at precisely the moment needed. The convergence of Hushai&rsquo;s return with Absalom&rsquo;s arrival is the divine coordination of events that the narrative will unfold in ch17: the counsel of Ahithophel counteracted at the exact moment it is given. The providential timing of grace — arriving precisely when needed — is what allows David&rsquo;s prayer of v31 to be answered in real time.</p>"
  },
  "16": {
    "1": "<p>A theme: Ziba meets the king with provisions at the moment of maximum vulnerability — the servant bringing food, wine, and donkeys to the fleeing king. The practical provision for the king in his exile is both historically accurate and theologically resonant: those who feed the king in his humiliation receive the king&rsquo;s gratitude. The eschatological judgment of Matt 25:35-40 (&lsquo;I was hungry and you fed me... whatever you did for one of the least of these brothers and sisters of mine, you did for me&rsquo;) is the fulfilment of this pattern.</p>",
    "2": "<p>A theme: Ziba&rsquo;s practical account of the provisions — food for the household, wine for the weary. The king in flight needs material care; Ziba provides what is needed without being asked. The servant who anticipates the king&rsquo;s needs is the model of the faithful steward: &lsquo;Well done, good and faithful servant... Come and share your master&rsquo;s happiness&rsquo; (Matt 25:21). Ziba&rsquo;s actual motives (to gain Mephibosheth&rsquo;s land) are mixed — but the practical service is genuine.</p>",
    "3": "<p>A shadow: Ziba&rsquo;s slander of Mephibosheth — &lsquo;He is staying in Jerusalem; he said, &ldquo;Today the house of Israel will restore my father&rsquo;s kingdom to me&rdquo;&rsquo; — the false accusation that turns the king against the innocent. False witness against the innocent before the king is the legal crime par excellence (Exod 23:1-3; Prov 25:18). It anticipates the false witnesses at Jesus&rsquo;s trial (Matt 26:59-61) who manufactured testimony to condemn the innocent. The king&rsquo;s provisional judgment on false testimony (v4) is the danger of human justice; the divine Judge&rsquo;s judgment will be fully accurate.</p>",
    "4": "<p>A theme: David grants Mephibosheth&rsquo;s land to Ziba on the basis of false testimony — a miscarriage of justice made from a position of weakness and information deprivation. David&rsquo;s flawed judgment in the crisis does not reflect the divine standard: &lsquo;You shall not distort justice; you shall not be partial&rsquo; (Deut 16:19). The contrast between the flawed human king&rsquo;s judgment and the perfect divine Judge (who later reverses the verdict, 19:29) establishes the superiority of Christ&rsquo;s judicial authority: his judgments are never distorted by crisis-information failures.</p>",
    "5": "<p>A type: Shimei son of Gera cursing the king as he leaves Bahurim — &lsquo;Get out! Get out! You man of blood! You worthless wretch!&rsquo; The cursing of the anointed king by a member of his own nation is the passion narrative&rsquo;s verbal abuse: the crowd&rsquo;s mocking of Jesus at the cross (&lsquo;Crucify him!&rsquo;; &lsquo;He saved others; he cannot save himself,&rsquo; Matt 27:40-42). David receives the curse in humility; Jesus received the taunts in silence (1 Pet 2:23: &lsquo;When he was reviled, he did not revile in return&rsquo;).</p>",
    "6": "<p>A type: Shimei throwing stones at the king and his servants as they fled — physical violence against the departing anointed. The combination of verbal abuse and physical aggression against the humiliated king is the passion narrative&rsquo;s structure: first the verbal mocking (the soldiers at the praetorium, Matt 27:27-31), then the physical violence. David&rsquo;s warriors are present but do not retaliate at the king&rsquo;s command (v10) — as the disciples did not retaliate at Gethsemane when Jesus commanded &lsquo;No more of this&rsquo; (Luke 22:51).</p>",
    "7": "<p>A type: &lsquo;Get out! Get out! You man of blood! You worthless wretch!&rsquo; — the specific terms of the curse are accusations of guilt: blood-guilt (<em>ʾîš haddāmîm</em>) and covenant-worthlessness (<em>ʾîš bəliyyaʿal</em>). The charge of bloodguilt against the anointed king is the same charge leveled against Jesus: &lsquo;Crucify him!... His blood be on us and on our children&rsquo; (Matt 27:22-25). Ironically, the very charge of bloodguilt against Christ is the mechanism by which his blood accomplishes redemption — his blood is &lsquo;on us&rsquo; exactly as the means of salvation (1 Pet 1:18-19).</p>",
    "8": "<p>A shadow: &lsquo;The LORD has repaid you for all the blood of the house of Saul, in whose place you have reigned.&rsquo; Shimei&rsquo;s theological interpretation of David&rsquo;s suffering — that it is divine punishment for bloodguilt — is partially true (there is divine discipline in David&rsquo;s suffering, 12:11-12) but fundamentally wrong as applied (David is innocent of Saul&rsquo;s blood). The charge of divine punishment against the innocent suffering king is the charge that Isaiah&rsquo;s suffering servant explicitly refutes: &lsquo;we esteemed him stricken, smitten by God, and afflicted. But he was pierced for our transgressions&rsquo; (Isa 53:4-5). The servant&rsquo;s suffering is not punishment for his own sin.</p>",
    "9": "<p>A theme: Abishai&rsquo;s demand for retributive justice — &lsquo;Why should this dead dog curse my lord the king? Let me go and cut off his head!&rsquo; — the loyal follower who wants to defend the king by force. This is Peter at Gethsemane cutting off Malchus&rsquo;s ear (John 18:10): the loyal impulsive defender who would use violence on behalf of the humiliated king. Both David and Jesus refuse the offered defense: the suffering must be accepted, not deflected by force.</p>",
    "10": "<p>A revelation of God: &lsquo;If the LORD has told him, &ldquo;Curse David,&rdquo; who can say, &ldquo;Why have you done this?&rdquo;&rsquo; — David&rsquo;s submission to the possibility that the curse is divinely permitted. This is not fatalism but the theological conviction that even adversity may be God&rsquo;s instrument of discipline or testing. The willingness to accept suffering as potentially within God&rsquo;s sovereign permission — rather than exclusively the work of human malice — is the posture of Christ in Gethsemane: &lsquo;if it is possible, let this cup pass from me; nevertheless, not as I will&rsquo; (Matt 26:39).</p>",
    "11": "<p>A type: &lsquo;My own son, my flesh and blood, is trying to kill me — how much more, then, this Benjaminite!&rsquo; — the anointed king who is being killed by his own son recognizes that external opposition is secondary to the betrayal from within. Jesus&rsquo;s passion is precisely the betrayal from within: Judas the apostle, the Jewish leadership of his own people, the denial of Peter. The suffering that comes from &lsquo;my own flesh and blood&rsquo; is the deepest form of rejection, and Christ received it at the maximum level.</p>",
    "12": "<p>A revelation of God: &lsquo;Perhaps the LORD will see my suffering (<em>ʿonyî</em>) and repay me with good for the cursing I receive today.&rsquo; David&rsquo;s hope that YHWH sees his suffering and will respond with good is the structure of Ps 22 and Ps 69 (both cited extensively in the passion narratives). The &lsquo;perhaps&rsquo; expresses faith under uncertainty — not certainty about the outcome but confidence in YHWH&rsquo;s character. The crucifixion&rsquo;s &lsquo;perhaps&rsquo; — the cry of desolation followed by confident commission (&lsquo;It is finished&rsquo;) — is David&rsquo;s uncertainty absolutized and then resolved by the resurrection.</p>",
    "13": "<p>A theme: The cursing king moving alongside on the opposite hillside, throwing stones and casting dust — the persistent opposition that accompanies the exiled king&rsquo;s entire journey. The adversary who follows alongside, cursing and stoning, is the picture of sustained spiritual opposition to the king&rsquo;s mission. Christ&rsquo;s temptations were not a single event but a pattern: &lsquo;When the devil had ended every temptation, he departed from him until an opportune time&rsquo; (Luke 4:13). The adversary who follows alongside on the opposite hill is the sustained opposition that the humiliated anointed one endures throughout the passion journey.</p>",
    "14": "<p>A theme: The king and all the people with him arriving exhausted at the Jordan and resting there. Exhaustion at the Jordan — the boundary of entry into the promised land — is the picture of the remnant church in its wilderness pilgrimage: worn out by the journey, resting at the boundary, not yet restored to the kingdom. The church&rsquo;s present condition is one of rest-at-the-Jordan: the kingdom promised, the exile ongoing, rest available but the full restoration still future (Heb 4:9-10: &lsquo;there remains a Sabbath rest for the people of God&rsquo;).</p>",
    "15": "<p>A shadow: Absalom and all the Israelites arrive in Jerusalem — the false king taking possession of the holy city. The occupation of Jerusalem by the false king who has stolen the hearts of the people is the eschatological anti-Christ pattern: &lsquo;He takes his seat in the temple of God, proclaiming himself to be God&rsquo; (2 Thess 2:4). The holy city occupied by the usurper while the true king is in exile is the structure of the present age from the NT&rsquo;s perspective: the kingdoms of the world in the hands of the one who claimed to own them (Luke 4:6).</p>",
    "16": "<p>A type: Hushai&rsquo;s ambiguous greeting — &lsquo;Long live the king! Long live the king!&rsquo; — without specifying which king he means. The spy&rsquo;s faithful deception operates by the double meaning of words that are true in their deeper referent while misleading on the surface. The prophetic speech of the OT functions similarly: texts that spoke truly of the historical David (or Solomon, or Hezekiah) carried a deeper reference to the Messiah that was not immediately visible. Hushai&rsquo;s ambiguous loyalty-speech is the narrative form of typological depth.</p>",
    "17": "<p>A theme: Absalom&rsquo;s challenge — &lsquo;Is this your loyalty to your friend?&rsquo; — frames fidelity in terms of personal attachment to David. The false king exposes the logic of his own usurpation in the question: loyalty belongs to the person of the king, not the office. This is why Hushai can serve David by serving Absalom — the king is the person, not the office-holder, and the office is temporarily occupied by an impostor. The theology of personal loyalty to the anointed person (not merely the institution) governs the NT&rsquo;s relationship to Jesus: it is attachment to the person of Christ, not merely membership in a religious institution.</p>",
    "18": "<p>A theme: Hushai&rsquo;s ambiguous profession — &lsquo;The one whom the LORD and this people and all Israel have chosen — to him I belong&rsquo; — uses language that is true of David (chosen by YHWH, 1 Sam 16:12-13) while being applied by Absalom to himself. The deep truth of the statement &lsquo;I serve the one YHWH chose&rsquo; is the NT principle that authentic service is determined by divine appointment, not popular acclaim. Hushai is telling the truth about his actual allegiance while Absalom hears it as about his own.</p>",
    "19": "<p>A theme: &lsquo;As I served your father, so I will serve you&rsquo; — the technically accurate claim that contains the loyalty-switch Absalom assumes. The continuity of covenantal service — serving the father and the son — is true for Hushai in ways Absalom cannot perceive. The NT&rsquo;s teaching on serving Christ applies the same principle: serving &lsquo;the Lord&rsquo; (YHWH) in the OT and serving &lsquo;the Lord&rsquo; (Christ) in the NT is service to the same divine King across the covenant discontinuity. Those who served David served the covenant God; those who serve Christ serve the same divine King now revealed in person.</p>",
    "20": "<p>A shadow: Absalom asking Ahithophel for counsel — &lsquo;Give us your advice&rsquo; — is the false king seeking the guidance of the traitor-counselor who has abandoned the true king. The irony is multilayered: Ahithophel is the wisest counselor in David&rsquo;s court (16:23), and his wisdom now serves the rebellion. The counsel that was given in YHWH&rsquo;s service is now deployed for YHWH&rsquo;s anointed&rsquo;s destruction. This is the distortion of wisdom that the NT calls the &lsquo;wisdom of this age&rsquo; — genuinely brilliant but turned against the purposes of God (1 Cor 1:20-21).</p>",
    "21": "<p>A type: Ahithophel&rsquo;s advice to violate David&rsquo;s concubines publicly — the formal declaration of Absalom&rsquo;s irreconcilable kingship. The advisor who counsels the most complete possible break with the legitimate king — using the king&rsquo;s own household to declare the rupture — is the Judas pattern maximized. Ahithophel&rsquo;s counsel produces the fulfillment of 12:11-12 (Nathan&rsquo;s prophecy that David&rsquo;s wives would be violated in public as consequence of his sin with Bathsheba). The traitor&rsquo;s counsel thus becomes the instrument of covenant discipline — even the worst betrayal operates within the purposes of the divine Judge.</p>",
    "22": "<p>A shadow: The public violation of David&rsquo;s concubines on the palace roof — the visible, humiliating demonstration of the usurper&rsquo;s kingship. The anointed king&rsquo;s household publicly violated as part of the false king&rsquo;s enthronement ceremony is the deepest point of David&rsquo;s humiliation in the narrative. The cross as the Roman Empire&rsquo;s most public, most humiliating execution method — &lsquo;he endured the cross, scorning its shame&rsquo; (Heb 12:2) — is the absolute version of the public humiliation of the true king.</p>",
    "23": "<p>A type: &lsquo;In those days the counsel Ahithophel gave was treated as if one had sought God&rsquo;s own word.&rsquo; Ahithophel as the counselor whose word carried divine authority — then used against God&rsquo;s anointed. The Judas pattern: Judas was one of the Twelve, bearer of apostolic authority, trusted with the common purse (John 12:6), whose word within the community carried apostolic weight. The one most trusted with genuine authority, when he betrays, does the most damage. Ahithophel&rsquo;s death by hanging (17:23) further seals the Judas type: both the betrayer of the anointed and Judas die by hanging after the failure of their counsel (Matt 27:5).</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '2samuel')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '2samuel', c)
    total = sum(len(v) for v in CHRIST.values())
    print(f'2samuel mkt-christ ch14-16: wrote {total} verses')

if __name__ == '__main__':
    main()
